@app.route("/login")
def login():
    if not OIDC_CLIENT_ID or not OIDC_AUTHORIZATION_ENDPOINT or not OIDC_TOKEN_ENDPOINT:
        abort(500, "OIDC configuration is incomplete")

    state = secrets.token_urlsafe(32)
    nonce = secrets.token_urlsafe(32)
    session["oidc_state"] = state
    session["oidc_nonce"] = nonce

    params = {
        "client_id": OIDC_CLIENT_ID,
        "response_type": "code",
        "scope": OIDC_SCOPE,
        "redirect_uri": OIDC_REDIRECT_URI,
        "state": state,
        "nonce": nonce,
    }

    authorize_url = f"{OIDC_AUTHORIZATION_ENDPOINT}?{urlencode(params)}"
    return redirect(authorize_url)


@app.route("/callback")
def callback():
    error = request.args.get("error")
    if error:
        return jsonify(
            {
                "error": error,
                "error_description": request.args.get("error_description"),
            }
        ), 400

    code = request.args.get("code")
    state = request.args.get("state")

    if not code or not state:
        return jsonify({"error": "Missing code or state"}), 400

    expected_state = session.get("oidc_state")
    if not expected_state or state != expected_state:
        return jsonify({"error": "Invalid state"}), 400

    token_data = {
        "grant_type": "authorization_code",
        "code": code,
        "redirect_uri": OIDC_REDIRECT_URI,
        "client_id": OIDC_CLIENT_ID,
        "client_secret": OIDC_CLIENT_SECRET,
    }

    token_response = requests.post(
        OIDC_TOKEN_ENDPOINT,
        data=token_data,
        headers={"Accept": "application/json"},
        timeout=15,
    )

    if token_response.status_code != 200:
        return jsonify(
            {
                "error": "Token exchange failed",
                "status_code": token_response.status_code,
                "response": token_response.text,
            }
        ), 400

    tokens = token_response.json()
    id_token = tokens.get("id_token")
    access_token = tokens.get("access_token")
    refresh_token = tokens.get("refresh_token")

    if not id_token:
        return jsonify({"error": "No id_token returned by provider"}), 400

    try:
        claims = decode_jwt_without_verification(id_token)
    except Exception as exc:
        return jsonify({"error": "Failed to decode id_token", "details": str(exc)}), 400

    expected_nonce = session.get("oidc_nonce")
    token_nonce = claims.get("nonce")
    if expected_nonce and token_nonce and expected_nonce != token_nonce:
        return jsonify({"error": "Invalid nonce"}), 400

    user = {
        "sub": claims.get("sub"),
        "name": claims.get("name"),
        "preferred_username": claims.get("preferred_username"),
        "email": claims.get("email"),
        "given_name": claims.get("given_name"),
        "family_name": claims.get("family_name"),
        "claims": claims,
    }

    if OIDC_USERINFO_ENDPOINT and access_token:
        try:
            userinfo_response = requests.get(
                OIDC_USERINFO_ENDPOINT,
                headers={"Authorization": f"Bearer {access_token}", "Accept": "application/json"},
                timeout=15,
            )
            if userinfo_response.status_code == 200:
                user["userinfo"] = userinfo_response.json()
        except requests.RequestException:
            pass

    session["user"] = user
    session["id_token"] = id_token
    session["access_token"] = access_token
    if refresh_token:
        session["refresh_token"] = refresh_token

    session.pop("oidc_state", None)
    session.pop("oidc_nonce", None)

    return redirect(url_for("profile"))


@app.route("/profile")
def profile():
    user = session.get("user")
    if not user:
        return redirect(url_for("login"))
    return jsonify({"user": user})


@app.route("/logout")
def logout():
    session.clear()
    return redirect(url_for("index"))


